module top_module(
    Q      ,
    CLK    ,
    RESET_B
);output reg [1:0] Q;
    input  CLK;
    input  RESET_B;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or negedge RESET_B or posedge dbg_halt) begin
        if (!RESET_B) begin
            Q <= 2'b00;
        end else begin
            Q <= Q + 1;
        end
    end

endmodule
